Method.Source:
 public void mapEntityToDataSource(DataEntityRuntimeContext _entityCtx, DataEntityDataSourceRuntimeContext _dataSourceCtx)
 {
     super(_entityCtx, _dataSourceCtx);

     if (_entityCtx.getDatabaseOperation() == DataEntityDatabaseOperation::Insert
     || _entityCtx.getDatabaseOperation() == DataEntityDatabaseOperation::Update)
     {
         if (_dataSourceCtx.name() == dataEntityDataSourceStr(TaxServiceTaxRegistrationNumberCustomerEntity, TaxRegistration))
         {  
             CustTable               custTable;
             DirPartyLocation        dirPartyLocation;
             LogisticsLocation logisticsLocation;
             LogisticsPostalAddress  postalAddress;

             select firstonly crosscompany custTable
                 where custTable.AccountNum == this.CustAccountNum
             join dirPartyLocation
                 where dirPartyLocation.Party == custTable.Party
             join logisticsLocation
                 where logisticsLocation.RecId == dirPartyLocation.Location
                    && logisticsLocation.LocationId == this.AddressLocationId;

             if (!dirPartyLocation.RecId)
             {
                 throw error(strFmt("No valid postal DirPartyLocation found for customer %1", this.CustAccountNum));
             }

             select firstOnly postalAddress
                 where postalAddress.Location == dirPartyLocation.Location;

             if (!postalAddress.RecId)
             {
                 throw error("No LogisticsPostalAddress found for selected DirPartyLocation");
             }

             TaxRegistrationType taxRegistrationType = TaxRegistrationType::findByType(this.TaxRegstrationType);
             TaxRegistrationTypeApplicabilityRule rule = TaxRegistrationTypeApplicabilityRule::findByTypeCountryId(taxRegistrationType.RecId, this.CountryRegionId);

             if (!rule.RecId)
             {
                 throw error(strFmt("No applicability rule found for Type %1 and Country %2",
                               this.TaxRegstrationType,
                               this.CountryRegionId));
             }

             TaxRegistration         taxRegistration = _dataSourceCtx.getBuffer();
             taxRegistration.DirPartyLocation = dirPartyLocation.RecId;
             taxRegistration.TaxRegistrationTypeApplicabilityRule = rule.RecId;
         }
     }
 }


